#include <dirent.h>
#include <string.h>
#include <sys/stat.h>
#include <stdlib.h>

/* == EXEMPLE ================================================
 * Compter les sous-repertoires dans /tmp
 * opendir() ouvre, readdir() itere, closedir() ferme.
 * =========================================================== */
void example_count_dirs(void) {
    DIR *dp = opendir("/tmp");
    if (!dp) { perror("opendir"); return; }
    struct dirent *entry;
    int dirs = 0;
    while ((entry = readdir(dp)) != NULL) {
        if (entry->d_type == DT_DIR &&
            strcmp(entry->d_name, ".") != 0 &&
            strcmp(entry->d_name, "..") != 0) {
            dirs++;
        }
    }
    closedir(dp);
    printf("Sous-repertoires dans /tmp : %d\n", dirs);
}
